// Route inbound Tai webhook payloads to the correct Kafka topic.
// Tai is configured to POST each webhook type to /tai?webhook_type=<type>.
// Kong has already enforced key-auth and stripped X-API-Key.
//
// Webhook type → topic mapping:
//   Financial  : bill_create, commission_bill_create   → tai-bills
//                invoice_create, invoice_create_with_shipment → tai-invoices
//   Shipment   : shipment_*                            → tai-shipments
//   Entity     : customer_create, customer_update      → tai-customers
//                carrier_create,  carrier_update       → tai-carriers
const item = $input.item.json;

const webhookType = (item.query && item.query.webhook_type) || item.webhook_type;
if (!webhookType) {
  const err = new Error('missing webhook_type query param');
  err.statusCode = 400;
  throw err;
}

const TOPIC_MAP = {
  bill_create:                        'tai-bills',
  commission_bill_create:             'tai-bills',
  invoice_create:                     'tai-invoices',
  invoice_create_with_shipment:       'tai-invoices',
  shipment_create:                    'tai-shipments',
  shipment_detail_update:             'tai-shipments',
  shipment_status_update:             'tai-shipments',
  shipment_location_update:           'tai-shipments',
  shipment_location_update_extended:  'tai-shipments',
  customer_create:                    'tai-customers',
  customer_update:                    'tai-customers',
  carrier_create:                     'tai-carriers',
  carrier_update:                     'tai-carriers',
};

const topic = TOPIC_MAP[webhookType];
if (!topic) {
  const err = new Error(`unsupported webhook_type: ${webhookType}`);
  err.statusCode = 400;
  throw err;
}

// Strip query/headers wrapper — Tai's actual payload is the POST body
const payload = item.body || item;

const event = {
  source:         'tai',
  webhook_type:   webhookType,
  payload,
  received_at:    new Date().toISOString(),
  correlation_id: $('Tai Webhook').first().json.headers?.['x-request-id'] || $execution.id,
  _key:           `tai:${webhookType}:${Date.now()}`,
  _topic:         topic,
};

return [{ json: event }];

const err = $input.item.json;
const status = err.statusCode || err.status || 500;
const isClient = status >= 400 && status < 500;
return {
  json: {
    workflow: 'tai-webhook-to-kafka',
    error:    err.message || err.error || 'unknown',
    status,
    is_client_error: isClient,
    original: err,
    timestamp: new Date().toISOString()
  }
};
